const alertas = $input.all().map(i => i.json);

if (alertas.length === 0) {
  return [{ json: { sin_alertas: true, total: 0 } }];
}

// Separar por severidad
const criticas = alertas.filter(a => a.severidad === 'critica' || a.severidad === 'alta');
const bajas    = alertas.filter(a => a.severidad === 'media'   || a.severidad === 'baja');

const resumen = {
  sin_alertas: false,
  total: alertas.length,
  criticas_count: criticas.length,
  bajas_count: bajas.length,
  hay_criticas: criticas.length > 0,
  // Construir HTML para email de críticas
  html_criticas: criticas.map(a => `
    <tr>
      <td style="padding:8px;border-bottom:1px solid #333;">
        <strong style="color:#ef4444">${a.severidad.toUpperCase()}</strong>
      </td>
      <td style="padding:8px;border-bottom:1px solid #333;">${a.lote_nombre} — ${a.finca_nombre}</td>
      <td style="padding:8px;border-bottom:1px solid #333;">${a.tipo}</td>
      <td style="padding:8px;border-bottom:1px solid #333;">${a.mensaje}</td>
      <td style="padding:8px;border-bottom:1px solid #333;color:#94a3b8;font-size:11px">${new Date(a.generada_en).toLocaleString('es-PE')}</td>
    </tr>`).join(''),
  // Construir HTML para resumen de bajas
  html_bajas: bajas.map(a => `
    <li style="margin-bottom:6px;color:#94a3b8">
      <strong style="color:#f59e0b">${a.severidad.toUpperCase()}</strong> — 
      ${a.lote_nombre}: ${a.mensaje}
    </li>`).join('')
};

return [{ json: resumen }];

